"use client";

import { useSignalStore } from "@/store/signalStore";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Activity } from "lucide-react";
import { useEffect, useState } from "react";
import { apiService } from "@/services/api";

export default function SettingsPage() {
  const [health, setHealth] = useState<unknown | null>(null);

  useEffect(() => {
    async function load() {
      try {
        const data = await apiService.getHealth();
        setHealth(data);
      } catch (err) {
        console.error(err);
      }
    }
    load();
  }, []);

  return (
    <div className="flex flex-col gap-6 max-w-4xl mx-auto text-white">
      <div className="flex flex-col gap-2">
        <h1 className="text-3xl font-bold tracking-tight">System Settings</h1>
        <p className="text-slate-400">Configuration and backend component health.</p>
      </div>

      <Card className="bg-slate-900 border-slate-800">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Activity className="h-5 w-5 text-indigo-400" />
            Backend Detailed Health
          </CardTitle>
        </CardHeader>
        <CardContent>
          {health ? (
             <pre className="bg-slate-950 p-4 rounded-xl border border-slate-800 text-sm font-mono text-emerald-400 overflow-x-auto">
               {JSON.stringify(health, null, 2)}
             </pre>
          ) : (
            <div className="py-8 text-center text-slate-500 font-mono">
              Loading backend health...
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import React, { useEffect, useRef } from "react";
import { createChart, IChartApi, ISeriesApi, ColorType } from "lightweight-charts";
import { useMarketStore } from "@/store/marketStore";
import { useSignalStore } from "@/store/signalStore";

export function TVChart() {
  const chartContainerRef = useRef<HTMLDivElement>(null);
  const chartRef = useRef<IChartApi | null>(null);
  const candlestickSeriesRef = useRef<ISeriesApi<"Candlestick"> | null>(null);
  const volumeSeriesRef = useRef<ISeriesApi<"Histogram"> | null>(null);

  const { liveKline, historicalData, symbol } = useMarketStore();
  const { prediction } = useSignalStore();

  useEffect(() => {
    if (!chartContainerRef.current) return;
    if (chartRef.current) return; // Prevent double initialization

    const chart = createChart(chartContainerRef.current, {
      layout: {
        background: { type: ColorType.Solid, color: 'transparent' },
        textColor: '#94a3b8', // slate-400
      },
      grid: {
        vertLines: { color: '#1e293b' }, // slate-800
        horzLines: { color: '#1e293b' },
      },
      crosshair: {
        mode: 0, // Normal
      },
      rightPriceScale: {
        borderColor: '#1e293b',
      },
      timeScale: {
        borderColor: '#1e293b',
        timeVisible: true,
        secondsVisible: false,
      },
      autoSize: true,
    });

    const candlestickSeries = chart.addCandlestickSeries({
      upColor: '#10b981', // emerald-500
      downColor: '#f43f5e', // rose-500
      borderVisible: false,
      wickUpColor: '#10b981',
      wickDownColor: '#f43f5e',
    });

    const volumeSeries = chart.addHistogramSeries({
      color: '#3b82f6',
      priceFormat: { type: 'volume' },
      priceScaleId: '', // set as an overlay
    });

    chart.priceScale('').applyOptions({
      scaleMargins: {
        top: 0.8,
        bottom: 0,
      },
    });

    chartRef.current = chart;
    candlestickSeriesRef.current = candlestickSeries;
    volumeSeriesRef.current = volumeSeries;

    if (historicalData && historicalData.length > 0) {
      // lightweight-charts needs time in seconds or string format
      candlestickSeries.setData(historicalData as any);
      const volumeData = historicalData.map(d => ({
        time: d.time,
        value: d.volume,
        color: d.close >= d.open ? '#059669' : '#e11d48' // slightly darker colors for volume
      }));
      volumeSeries.setData(volumeData as any);
    }

    return () => {
      chart.remove();
      chartRef.current = null;
    };
  }, []); // Only initialization

  // Update real-time 
  useEffect(() => {
    if (candlestickSeriesRef.current && volumeSeriesRef.current && liveKline) {
      // lightweight-charts needs time in seconds or string format
      candlestickSeriesRef.current.update(liveKline as any);

      volumeSeriesRef.current.update({
        time: liveKline.time,
        value: liveKline.volume,
        color: liveKline.close >= liveKline.open ? '#059669' : '#e11d48'
      } as any);
    }
  }, [liveKline]);

  // Handle Signal Markers
  useEffect(() => {
    if (candlestickSeriesRef.current && prediction) {
      const latestTime = liveKline?.time || (historicalData.length > 0 ? historicalData[historicalData.length - 1].time : null);
      if (latestTime && (prediction.signal === 'BUY' || prediction.signal === 'SELL')) {
        (candlestickSeriesRef.current as any).setMarkers([
          {
            time: latestTime as any,
            position: prediction.signal === 'BUY' ? 'belowBar' : 'aboveBar',
            color: prediction.signal === 'BUY' ? '#10b981' : '#f43f5e',
            shape: prediction.signal === 'BUY' ? 'arrowUp' : 'arrowDown',
            text: prediction.signal,
          }
        ]);
      } else {
        (candlestickSeriesRef.current as any).setMarkers([]);
      }
    }
  }, [prediction, liveKline, historicalData]);

  return (
    <div className="w-full h-full min-h-[400px] flex flex-col rounded-xl border border-slate-800 bg-slate-900/50 backdrop-blur-xl overflow-hidden shadow">
      <div className="flex items-center justify-between px-4 py-3 border-b border-slate-800 bg-slate-900/80">
        <h3 className="font-semibold text-slate-100">{symbol}</h3>
        <span className="text-xs font-medium text-emerald-400 bg-emerald-500/10 px-2.5 py-1 rounded border border-emerald-500/20 flex items-center gap-1.5">
          <span className="relative flex h-2 w-2">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-2 w-2 bg-emerald-500"></span>
          </span>
          Live
        </span>
      </div>
      <div ref={chartContainerRef} className="flex-1 w-full relative" />
    </div>
  );
}

