"use client";

import React, { useState, useEffect, useMemo } from "react";
import { motion } from "framer-motion";
import { useWebSocket } from "@/hooks/useWebSocket";
import {
  GlassCard,
  MetricCard,
  SignalBadge,
  LiveIndicator,
} from "@/components/ui/animated-components";
import {
  TrendingUp,
  Wallet,
  Target,
  Activity,
} from "lucide-react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
} from "recharts";

import { TVChart } from "@/components/charts/TVChart";
import { LiveTradingPanel, type Position } from "./live-trading-panel";
import { RiskDashboard } from "./risk-dashboard";
import { SystemHealth } from "./system-health";
import { apiService } from "@/services/api";


interface PortfolioData {
  timestamp: string;
  equity: number;
  cash: number;
  unrealized_pnl: number;
  realized_pnl: number;
  total_return: number;
  positions?: Record<string, Position>;
}

interface SignalData {
  symbol: string;
  direction: "BUY" | "SELL" | "HOLD";
  confidence: number;
  probability: number;
  regime: string;
  price?: number;
  timestamp?: string;
}

interface MetricsData {
  timestamp: string;
  win_rate: number;
  sharpe_ratio: number;
  max_drawdown: number;
  total_trades: number;
  profitable_trades: number;
  avg_win: number;
  avg_loss: number;
}

interface MarketData {
  symbol: string;
  price: number;
  volume: number;
  change_percent: number;
  timestamp: string;
}

export function ModernDashboard() {
  const [equityHistory, setEquityHistory] = useState<
    Array<{ time: string; equity: number }>
  >([]);
  const [symbol, setSymbol] = useState("BTCUSDT");
  const [apiHealth, setApiHealth] = useState<"active" | "inactive" | "warning" | "error">("inactive");

  // WebSocket connections
  const { data: portfolioData, isConnected: portfolioConnected } =
    useWebSocket<PortfolioData>(`/ws/portfolio`);
  const { data: signalData, isConnected: signalConnected } =
    useWebSocket<SignalData>(`/ws/signals?symbol=${symbol}`);
  const { data: metricsData, isConnected: metricsConnected } =
    useWebSocket<MetricsData>(`/ws/metrics`);
  const { data: marketData, isConnected: marketConnected } =
    useWebSocket<MarketData>(`/ws/market?symbol=${symbol}`);

  useEffect(() => {
    // Basic API health check
    const checkApi = async () => {
      try {
        await apiService.getHealth();
        setApiHealth("active");
      } catch (e) {
        setApiHealth("error");
      }
    };
    checkApi();
    const interval = setInterval(checkApi, 30000);
    return () => clearInterval(interval);
  }, []);

  // Track equity history
  useEffect(() => {
    if (portfolioData?.equity) {
      setEquityHistory((prev) => {
        const timestamp = portfolioData.timestamp 
          ? new Date(portfolioData.timestamp).toLocaleTimeString() 
          : new Date().toLocaleTimeString();

        return [
          ...prev.slice(-24),
          {
            time: timestamp,
            equity: portfolioData.equity,
          },
        ];
      });
    }
  }, [portfolioData?.equity]);

  const allConnected = useMemo(() => 
    portfolioConnected &&
    signalConnected &&
    metricsConnected &&
    marketConnected &&
    apiHealth === "active",
  [portfolioConnected, signalConnected, metricsConnected, marketConnected, apiHealth]);

  const equityTrend = useMemo(() => 
    equityHistory.length > 1
      ? ((equityHistory[equityHistory.length - 1].equity -
          equityHistory[equityHistory.length - 2].equity) /
          equityHistory[equityHistory.length - 2].equity) *
        100
      : 0,
  [equityHistory]);

  const cashTrend = useMemo(() => 
    portfolioData?.equity
      ? ((portfolioData?.cash || 0) / portfolioData?.equity) * 100 - 100
      : 0,
  [portfolioData?.equity, portfolioData?.cash]);

  // Derive risk limits
  const maxDrawdown = useMemo(() => metricsData?.max_drawdown || 0, [metricsData?.max_drawdown]);

  const leverage = useMemo(() => 
    portfolioData?.equity && portfolioData.positions
      ? Object.values(portfolioData.positions).reduce((acc: number, pos: Position) => acc + (pos.size * pos.current_price), 0) / portfolioData.equity
      : 0,
  [portfolioData?.equity, portfolioData?.positions]);

  const exposurePct = useMemo(() => 
    portfolioData?.equity && portfolioData.positions
      ? Object.values(portfolioData.positions).reduce((acc: number, pos: Position) => acc + Math.abs(pos.size * pos.current_price), 0) / portfolioData.equity
      : 0,
  [portfolioData?.equity, portfolioData?.positions]);

  const dailyLossPct = useMemo(() => 
    portfolioData?.equity 
      ? (portfolioData.unrealized_pnl + portfolioData.realized_pnl) / portfolioData.equity
      : 0,
  [portfolioData?.equity, portfolioData?.unrealized_pnl, portfolioData?.realized_pnl]);

  const riskStatus = useMemo(() => 
    maxDrawdown < -0.1 ? "CRITICAL" : maxDrawdown < -0.05 ? "ELEVATED" : "NORMAL",
  [maxDrawdown]);

  return (
    <div className="space-y-6 pb-6">
      {/* Header with Live Status */}
      <motion.div
        className="flex items-center justify-between"
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <div>
          <h1 className="text-3xl font-bold tracking-tight text-white mb-1">
            Institutional Dashboard
          </h1>
          <p className="text-sm text-slate-400">
            Real-time market insights and algorithmic execution
          </p>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex gap-1.5 bg-slate-800/50 p-1.5 rounded-lg border border-slate-700/50">
            {[
              { connected: portfolioConnected, label: "PF" },
              { connected: signalConnected, label: "SIG" },
              { connected: metricsConnected, label: "MET" },
              { connected: marketConnected, label: "MKT" },
            ].map(({ connected, label }) => (
              <div
                key={label}
                className={`px-2 py-1 rounded text-[10px] font-bold tracking-wide ${
                  connected
                    ? "bg-emerald-500/20 text-emerald-400"
                    : "bg-red-500/20 text-red-400"
                }`}
              >
                {label}
              </div>
            ))}
          </div>
          <LiveIndicator
            isConnected={allConnected}
            label={allConnected ? "System Online" : "Degraded"}
            dotSize="md"
          />
        </div>
      </motion.div>

      {/* Key Metrics Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4">
        <MetricCard
          label="Total Equity"
          value={portfolioData?.equity.toFixed(2) || "10000.00"}
          change={equityTrend}
          unit=" USD"
          icon={<Wallet className="w-5 h-5 text-blue-400" />}
          trend={equityTrend > 0 ? "up" : equityTrend < 0 ? "down" : "neutral"}
          delay={0}
        />
        <MetricCard
          label="Available Capital"
          value={portfolioData?.cash.toFixed(2) || "10000.00"}
          unit=" USD"
          icon={<TrendingUp className="w-5 h-5 text-emerald-400" />}
          trend={cashTrend > 0 ? "up" : "down"}
          delay={0.1}
        />
        <MetricCard
          label="Win Rate"
          value={((metricsData?.win_rate || 0.0) * 100).toFixed(1)}
          unit="%"
          icon={<Target className="w-5 h-5 text-indigo-400" />}
          trend={(metricsData?.win_rate || 0) > 0.5 ? "up" : "down"}
          delay={0.2}
        />
        <MetricCard
          label="Sharpe Ratio"
          value={(metricsData?.sharpe_ratio || 0.0).toFixed(2)}
          icon={<Activity className="w-5 h-5 text-purple-400" />}
          trend={(metricsData?.sharpe_ratio || 0) > 1 ? "up" : "neutral"}
          delay={0.3}
        />
      </div>

      {/* Main Content Grid */}
      <div className="grid grid-cols-1 xl:grid-cols-12 gap-6">

        {/* Left Column (Chart & Live Trading) */}
        <div className="xl:col-span-8 flex flex-col gap-6">
          {/* Advanced Chart System */}
          <div className="h-[450px]">
            <TVChart />
          </div>

          {/* Live Trading Panel */}
          <div className="h-[300px]">
             <LiveTradingPanel 
               positions={portfolioData?.positions} 
               loading={!portfolioConnected} 
             />
          </div>

          {/* Strategy Analytics / Equity Curve */}
          <GlassCard className="h-[300px]">
            <div className="flex items-center justify-between mb-4">
              <div>
                <h3 className="text-lg font-semibold text-white">
                  Strategy Analytics
                </h3>
                <p className="text-xs text-slate-400">24-hour performance distribution</p>
              </div>
              <div className="px-3 py-1.5 rounded-lg bg-blue-500/10 border border-blue-500/30 text-blue-300 text-xs font-medium">
                {equityHistory.length > 0 ? "+" : ""}{" "}
                {equityHistory.length > 1
                  ? (
                      equityHistory[equityHistory.length - 1].equity -
                      equityHistory[0].equity
                    ).toFixed(2)
                  : "0.00"}{" "}
                USD
              </div>
            </div>

            {equityHistory.length > 0 ? (
              <ResponsiveContainer width="100%" height={200}>
                <LineChart data={equityHistory}>
                  <defs>
                    <linearGradient
                      id="colorEquity"
                      x1="0"
                      y1="0"
                      x2="0"
                      y2="1"
                    >
                      <stop offset="5%" stopColor="#818cf8" stopOpacity={0.8} />
                      <stop offset="95%" stopColor="#818cf8" stopOpacity={0.0} />
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" vertical={false} />
                  <XAxis dataKey="time" stroke="rgba(255,255,255,0.2)" style={{ fontSize: "10px" }} tickMargin={10} />
                  <YAxis stroke="rgba(255,255,255,0.2)" style={{ fontSize: "10px" }} domain={['auto', 'auto']} tickMargin={10} />
                  <Tooltip
                    contentStyle={{ backgroundColor: "rgba(15, 23, 42, 0.9)", border: "1px solid rgba(255,255,255,0.1)", borderRadius: "8px" }}
                  />
                  <Line type="monotone" dataKey="equity" stroke="#818cf8" strokeWidth={2} dot={false} fill="url(#colorEquity)" />
                </LineChart>
              </ResponsiveContainer>
            ) : (
                <div className="h-[200px] flex items-center justify-center text-slate-500 text-sm">Waiting for equity data...</div>
            )}
          </GlassCard>
        </div>

        {/* Right Column (Side Panels) */}
        <div className="xl:col-span-4 flex flex-col gap-6">

          {/* Current Signal Panel */}
          <GlassCard className="h-fit">
            <div className="flex justify-between items-start mb-4">
              <div>
                <h3 className="text-lg font-semibold text-white">Alpha Signal</h3>
                <p className="text-xs text-slate-400">Current AI recommendation</p>
              </div>
              <span className="font-mono text-sm font-bold text-slate-300 bg-slate-800 px-2 py-1 rounded">
                {symbol}
              </span>
            </div>

            <div className="flex justify-center mb-6 mt-2">
              <SignalBadge
                signal={(signalData?.direction as "BUY" | "SELL" | "HOLD") || "HOLD"}
                confidence={signalData?.confidence || 0.5}
                size="lg"
              />
            </div>

            <div className="space-y-3 bg-slate-900/50 rounded-xl p-4 border border-white/5">
              <div className="flex justify-between text-sm">
                <span className="text-slate-400">Probability</span>
                <span className="text-white font-medium">
                  {((signalData?.probability || 0) * 100).toFixed(1)}%
                </span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-slate-400">Regime</span>
                <span className="text-indigo-400 font-medium tracking-wide text-xs mt-0.5">
                  {signalData?.regime || "NEUTRAL"}
                </span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-slate-400">Current Price</span>
                <span className="text-white font-medium font-mono">
                  ${(marketData?.price || 0).toFixed(2)}
                </span>
              </div>
            </div>
          </GlassCard>

          {/* Risk Dashboard */}
          <div className="h-fit flex-1 min-h-[250px]">
            <RiskDashboard 
              exposurePct={exposurePct}
              leverage={leverage}
              dailyLossPct={dailyLossPct}
              maxDrawdown={maxDrawdown}
              riskStatus={riskStatus as "CRITICAL" | "ELEVATED" | "NORMAL"}
              loading={!portfolioConnected}
            />
          </div>

          {/* System Health */}
          <div className="h-fit min-h-[200px]">
            <SystemHealth 
              apiStatus={apiHealth}
              wsStatus={marketConnected || portfolioConnected ? "active" : "warning"}
              modelStatus={signalConnected ? "active" : "warning"}
              latency={42} // Fixed latency display or hook it up later
              lastUpdate={new Date().toLocaleTimeString()}
            />
          </div>

        </div>
      </div>
    </div>
  );
}

"use client";

import React from "react";
import { motion } from "framer-motion";
import { GlassCard } from "@/components/ui/animated-components";
import { ShieldAlert, Activity, AlertTriangle, ShieldCheck } from "lucide-react";

interface RiskDashboardProps {
  exposurePct?: number; 
  leverage?: number;
  dailyLossPct?: number;
  maxDrawdown?: number;
  riskStatus?: "NORMAL" | "ELEVATED" | "CRITICAL";
  loading?: boolean;
}

export function RiskDashboard({
  exposurePct = 0,
  leverage = 0,
  dailyLossPct = 0,
  maxDrawdown = 0,
  riskStatus = "NORMAL",
  loading = false,
}: RiskDashboardProps) {

  const statusConfig = {
    NORMAL: { color: "text-emerald-400", bg: "bg-emerald-500/10", border: "border-emerald-500/20", icon: ShieldCheck },
    ELEVATED: { color: "text-amber-400", bg: "bg-amber-500/10", border: "border-amber-500/20", icon: AlertTriangle },
    CRITICAL: { color: "text-red-400", bg: "bg-red-500/10", border: "border-red-500/20", icon: ShieldAlert },
  };

  const currentStatus = statusConfig[riskStatus];
  const StatusIcon = currentStatus.icon;

  return (
    <GlassCard className="h-full flex flex-col">
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-2">
          <Activity className="w-5 h-5 text-indigo-400" />
          <h3 className="text-lg font-semibold text-white">Risk Metrics</h3>
        </div>
        <div className={`px-2.5 py-1 rounded flex items-center gap-1.5 border ${currentStatus.bg} ${currentStatus.border} ${currentStatus.color} text-xs font-bold tracking-wider`}>
          <StatusIcon className="w-3.5 h-3.5" />
          {riskStatus}
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4 flex-1">
        {/* Exposure */}
        <div className="p-4 rounded-xl bg-slate-800/30 border border-white/5 space-y-2">
          <p className="text-xs font-medium text-slate-400 uppercase">Gross Exposure</p>
          <div className="flex items-end gap-2">
            <span className="text-2xl font-bold text-white">{(exposurePct * 100).toFixed(1)}%</span>
          </div>
          <div className="w-full bg-slate-700/50 rounded-full h-1.5 mt-2">
            <motion.div 
              className={`h-full rounded-full ${exposurePct > 0.8 ? "bg-red-500" : exposurePct > 0.5 ? "bg-amber-500" : "bg-emerald-500"}`}
              initial={{ width: 0 }}
              animate={{ width: `${Math.min(exposurePct * 100, 100)}%` }}
              transition={{ duration: 1, ease: "easeOut" }}
            />
          </div>
        </div>

        {/* Leverage */}
        <div className="p-4 rounded-xl bg-slate-800/30 border border-white/5 space-y-2">
          <p className="text-xs font-medium text-slate-400 uppercase">Effective Leverage</p>
          <div className="flex items-end gap-2">
            <span className="text-2xl font-bold text-white">{leverage.toFixed(2)}x</span>
          </div>
          <div className="w-full bg-slate-700/50 rounded-full h-1.5 mt-2">
            <motion.div 
              className={`h-full rounded-full ${leverage > 3 ? "bg-red-500" : leverage > 1.5 ? "bg-amber-500" : "bg-blue-500"}`}
              initial={{ width: 0 }}
              animate={{ width: `${Math.min((leverage / 5) * 100, 100)}%` }}
              transition={{ duration: 1, ease: "easeOut" }}
            />
          </div>
        </div>

        {/* Daily Loss */}
        <div className="p-4 rounded-xl bg-slate-800/30 border border-white/5 space-y-2">
          <p className="text-xs font-medium text-slate-400 uppercase">Daily Loss</p>
          <div className="flex items-end gap-2">
            <span className={`text-2xl font-bold ${dailyLossPct < -0.02 ? "text-red-400" : "text-white"}`}>
              {(dailyLossPct * 100).toFixed(2)}%
            </span>
          </div>
          <p className="text-[10px] text-slate-500">Limit: -3.00%</p>
        </div>

        {/* Max Drawdown */}
        <div className="p-4 rounded-xl bg-slate-800/30 border border-white/5 space-y-2">
          <p className="text-xs font-medium text-slate-400 uppercase">Max Drawdown</p>
          <div className="flex items-end gap-2">
            <span className={`text-2xl font-bold ${maxDrawdown < -0.05 ? "text-amber-400" : "text-white"}`}>
              {Math.abs(maxDrawdown * 100).toFixed(2)}%
            </span>
          </div>
          <p className="text-[10px] text-slate-500">Peak-to-trough</p>
        </div>
      </div>
    </GlassCard>
  );
}

