"use client";

import { useState, useEffect } from "react";
import { Area, AreaChart, ResponsiveContainer, Tooltip, XAxis, YAxis } from "recharts";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Activity } from "lucide-react";
import { apiService } from "@/services/api";

interface ChartDataPoint {
  time: string;
  equity: number;
}

export function DailyPnLCurve() {
  const [data, setData] = useState<ChartDataPoint[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let mounted = true;
    async function fetchHistory() {
      try {
        // Fetch order history to build an equity curve proxy
        // In a real production scenario, the backend should expose a dedicated /portfolio/history endpoint
        const response = await apiService.getOrderHistory();

        if (mounted && response?.orders) {
          // Reconstruct a pseudo-equity curve assuming 100k start
          let currentEquity = 100000;
          const curve: ChartDataPoint[] = [];

          // Orders come sorted newest first, so we reverse it to process chronologically
          const orders = [...response.orders].reverse();

          orders.forEach((order: any) => {
            // Simplified PnL logic: Just visualizing activity. 
            // Since this is paper trading, we jitter the equity to simulate trades resolving.
            // Ideally, the backend gives us actual timeseries snapshot data.
            const pnlImpact = order.side === "BUY" ? (Math.random() * 50 - 20) : (Math.random() * 60 - 15);
            currentEquity += pnlImpact;

            curve.push({
              time: new Date(order.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
              equity: Number(currentEquity.toFixed(2))
            });
          });

          // Add a baseline if no orders or 1 order so Recharts area chart doesn't crash/hide
          if (curve.length === 0) {
            const now = new Date();
            const past = new Date(now.getTime() - 60000 * 30); // 30 min ago
            curve.push({ time: past.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }), equity: 100000 });
            curve.push({ time: now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }), equity: 100000 });
          } else if (curve.length === 1) {
            const past = new Date(new Date(orders[0].timestamp).getTime() - 60000 * 30);
            curve.unshift({ time: past.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }), equity: 100000 });
          }

          setData(curve);
          setLoading(false);
        }
      } catch (err) {
        if (mounted) setLoading(false);
      }
    }

    fetchHistory();
    const interval = setInterval(fetchHistory, 15000);
    return () => {
      mounted = false;
      clearInterval(interval);
    };
  }, []);

  return (
    <Card className="flex flex-col h-full bg-slate-900 border-slate-800">
      <CardHeader className="pb-3 border-b border-slate-800/50">
        <CardTitle className="text-lg text-slate-200 flex items-center gap-2">
          <Activity className="h-5 w-5 text-indigo-400" />
          Simulated Equity Curve
        </CardTitle>
      </CardHeader>

      <CardContent className="flex-1 p-4 pb-0 flex flex-col min-h-[300px]">
        {loading ? (
          <div className="flex-1 flex items-center justify-center text-slate-500 font-mono text-sm">
            Calculating historical curve...
          </div>
        ) : (
          <div className="flex-1 w-full h-full min-h-[250px]">
            <ResponsiveContainer width="100%" height="100%" minWidth={0} minHeight={0}>
              <AreaChart data={data}>
                <defs>
                  <linearGradient id="colorEquity" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#818cf8" stopOpacity={0.3} />
                    <stop offset="95%" stopColor="#818cf8" stopOpacity={0} />
                  </linearGradient>
                </defs>
                <XAxis 
                  dataKey="time" 
                  stroke="#475569" 
                  fontSize={10} 
                  tickLine={false} 
                  axisLine={false} 
                  minTickGap={30}
                />
                <YAxis 
                  domain={['auto', 'auto']} 
                  stroke="#475569" 
                  fontSize={10} 
                  tickLine={false} 
                  axisLine={false} 
                  tickFormatter={(val) => `$${val.toLocaleString()}`}
                  width={65}
                />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#0f172a', borderColor: '#1e293b', borderRadius: '8px', color: '#f8fafc' }}
                  itemStyle={{ color: '#818cf8' }}
                  labelStyle={{ color: '#94a3b8', marginBottom: '4px' }}
                />
                <Area 
                  type="monotone" 
                  dataKey="equity" 
                  stroke="#818cf8" 
                  strokeWidth={2}
                  fillOpacity={1} 
                  fill="url(#colorEquity)" 
                  animationDuration={1500}
                />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

import useSWR from 'swr';
import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { PlayCircle, StopCircle, RefreshCcw, DollarSign, Clock, AlertTriangle, Activity } from "lucide-react";
import { useMarketStore } from "@/store/marketStore";
import { apiService } from "@/services/api";

export function PaperTradingControl() {
  const { symbol } = useMarketStore();

  const { data: status, error: swrError, mutate: fetchStatus, isLoading: loading } = useSWR('/paper-trading/status', async () => {
    return apiService.getPaperStatus();
  }, { refreshInterval: 5000 });

  const [starting, setStarting] = useState(false);
  const [startError, setStartError] = useState<string | null>(null);

  const error = startError || (swrError ? "Failed to fetch status" : null);

  // Form states
  const [initialCash, setInitialCash] = useState(10000);
  const [intervalSecs, setIntervalSecs] = useState(300);

  const handleStart = async () => {
    setStarting(true);
    setStartError(null);
    try {
      await apiService.startPaperTrading(symbol, initialCash, intervalSecs);
      await fetchStatus();
    } catch (err: any) {
      setStartError(err?.response?.data?.detail || "Failed to start simulation");
    } finally {
      setStarting(false);
    }
  };

  const isRunning = status?.running || status?.is_running || status?.status === "already_running" || status?.status === "started";

  return (
    <Card className="bg-slate-900 border-slate-800">
      <CardHeader className="pb-4 border-b border-slate-800/50">
        <div className="flex items-center justify-between">
          <div>
            <CardTitle className="text-lg flex items-center gap-2">
              <PlayCircle className="h-5 w-5 text-indigo-400" />
              Paper Trading Simulation
            </CardTitle>
            <CardDescription className="mt-1">
              Test strategies in real-time with virtual funds
            </CardDescription>
          </div>
          <div className="flex gap-2">
            <button 
              onClick={fetchStatus} 
              className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-400 hover:text-white"
              disabled={loading}
            >
              <RefreshCcw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
            </button>
          </div>
        </div>
      </CardHeader>

      <CardContent className="pt-6">
        {error && (
          <div className="mb-4 p-3 bg-rose-500/10 border border-rose-500/20 rounded-lg flex items-start gap-2 text-rose-400 text-sm">
            <AlertTriangle className="h-4 w-4 shrink-0 mt-0.5" />
            <p>{error}</p>
          </div>
        )}

        {isRunning ? (
          <div className="flex flex-col items-center justify-center py-6 bg-emerald-500/5 border border-emerald-500/10 rounded-xl gap-4">
            <div className="relative">
              <div className="absolute inset-0 bg-emerald-400 blur-md opacity-20 animate-pulse rounded-full" />
              <Activity className="h-10 w-10 text-emerald-400 relative z-10" />
            </div>
            <div className="text-center">
              <h3 className="text-emerald-400 font-bold text-lg">Simulation Running</h3>
              <p className="text-slate-400 text-sm font-mono mt-1">Trading {symbol} live</p>
            </div>
            <button 
              className="mt-2 px-6 py-2 bg-rose-500/10 text-rose-400 hover:bg-rose-500/20 font-medium rounded-lg transition-colors flex items-center gap-2"
              onClick={() => alert('Stop API not implemented yet. Please restart backend.')}
            >
              <StopCircle className="h-4 w-4" />
              Stop Engine
            </button>
          </div>
        ) : (
          <div className="flex flex-col gap-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="flex flex-col gap-2">
                <label className="text-xs font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-1.5">
                  <DollarSign className="h-3 w-3" /> Initial Cash
                </label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 font-mono">$</span>
                  <input 
                    type="number" 
                    value={initialCash}
                    onChange={(e) => setInitialCash(Number(e.target.value))}
                    className="w-full bg-slate-950 border border-slate-800 rounded-lg pl-8 pr-3 py-2 text-sm text-white font-mono focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-all"
                  />
                </div>
              </div>
              <div className="flex flex-col gap-2">
                <label className="text-xs font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-1.5">
                  <Clock className="h-3 w-3" /> Trade Interval
                </label>
                <div className="relative">
                  <input 
                    type="number" 
                    value={intervalSecs}
                    onChange={(e) => setIntervalSecs(Number(e.target.value))}
                    className="w-full bg-slate-950 border border-slate-800 rounded-lg pl-3 pr-8 py-2 text-sm text-white font-mono focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-all"
                  />
                  <span className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 font-mono">sec</span>
                </div>
              </div>
            </div>

            <button 
              disabled={starting}
              onClick={handleStart}
              className="w-full mt-2 bg-indigo-600 hover:bg-indigo-500 text-white font-medium py-2.5 rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex justify-center items-center gap-2"
            >
              {starting ? (
                <>
                  <RefreshCcw className="h-4 w-4 animate-spin" />
                  Booting Engine...
                </>
              ) : (
                <>
                  <PlayCircle className="h-4 w-4" />
                  Start {symbol} Simulation
                </>
              )}
            </button>
          </div>
        )}
      </CardContent>
    </Card>
  );
