    sm: "px-2 py-1 text-xs",
    md: "px-3 py-1.5 text-sm",
    lg: "px-4 py-2 text-base",
  };

  const config = signalConfig[signal];

  return (
    <motion.div
      className={`
        rounded-lg border ${config.bg} ${config.border} ${sizeMap[size]}
        flex items-center gap-2 w-fit font-medium ${config.text}
      `}
      animate={animated ? { scale: [1, 1.05, 1] } : {}}
      transition={animated ? { duration: 2, repeat: Infinity } : {}}
    >
      <Radio className="w-3 h-3 animate-pulse" />
      <span>{signal}</span>
      <span className="text-xs opacity-75">
        ({(confidence * 100).toFixed(0)}%)
      </span>
    </motion.div>
  );
}

interface AnimatedChartProps {
  data: Array<{ x: number; y: number }>;
  children?: React.ReactNode;
  height?: number;
  delay?: number;
}

export function AnimatedChart({
  data,
  children,
  height = 300,
  delay = 0,
}: AnimatedChartProps) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5, delay }}
      className="w-full"
      style={{ height }}
    >
      {children}
    </motion.div>
  );
}

interface StatusDotProps {
  status: "active" | "inactive" | "warning" | "error";
  animated?: boolean;
  label?: string;
}

export function StatusDot({ status, animated = true, label }: StatusDotProps) {
  const statusConfig = {
    active: "bg-emerald-400 shadow-lg shadow-emerald-400/50",
    inactive: "bg-slate-600",
    warning: "bg-amber-400 shadow-lg shadow-amber-400/50",
    error: "bg-red-400 shadow-lg shadow-red-400/50",
  };

  return (
    <div className="flex items-center gap-2">
      <motion.div
        className={`w-2.5 h-2.5 rounded-full ${statusConfig[status]}`}
        animate={animated ? { scale: [1, 1.3, 1], opacity: [1, 0.8, 1] } : {}}
        transition={animated ? { duration: 2, repeat: Infinity } : {}}
      />
      {label && <span className="text-xs text-slate-400">{label}</span>}
    </div>
  );
}

"use client";

import React from "react";
import { motion } from "framer-motion";
import { GlassCard } from "./animated-components";
import {
  PieChart,
  Pie,
  Cell,
  ResponsiveContainer,
  Legend,
  Tooltip,
} from "recharts";
import { Activity, TrendingUp, TrendingDown } from "lucide-react";

interface PortfolioPosition {
  symbol: string;
  quantity: number;
  entryPrice: number;
  currentPrice: number;
  value: number;
  pnl: number;
  pnlPercent: number;
}

interface PortfolioOverviewProps {
  totalEquity: number;
  totalCash: number;
  positions: PortfolioPosition[];
  unrealizedPnl: number;
  realizedPnl: number;
}

export function PortfolioOverview({
  totalEquity,
  totalCash,
  positions,
  unrealizedPnl,
  realizedPnl,
}: PortfolioOverviewProps) {
  const totalAllocated = totalEquity - totalCash;
  const cashPercentage = (totalCash / totalEquity) * 100;
  const allocatedPercentage = ((totalEquity - totalCash) / totalEquity) * 100;

  const pieData = [
    { name: "Allocated", value: allocatedPercentage },
    { name: "Cash", value: cashPercentage },
  ];

  const COLORS = ["#06b6d4", "#1e293b"];

  return (
    <div className="space-y-6">
      <GlassCard>
        <div className="space-y-4">
          <h3 className="text-lg font-semibold text-white">
            Portfolio Allocation
          </h3>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {/* Pie Chart */}
            <ResponsiveContainer width="100%" height={200}>
              <PieChart>
                <Pie
                  data={pieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={90}
                  paddingAngle={2}
                  dataKey="value"
                >
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index]} />
                  ))}
                </Pie>
                <Tooltip
                  contentStyle={{
                    backgroundColor: "rgba(15, 23, 42, 0.9)",
                    border: "1px solid rgba(255,255,255,0.1)",
                    borderRadius: "8px",
                    color: "white",
                  }}
                />
              </PieChart>
            </ResponsiveContainer>

            {/* Stats */}
            <div className="space-y-3">
              <motion.div
                className="p-3 rounded-lg bg-white/5 border border-white/10"
                whileHover={{ scale: 1.02 }}
              >
                <p className="text-xs font-medium text-slate-400 uppercase">
                  Total Equity
                </p>
                <motion.p
                  className="text-2xl font-bold text-cyan-400 mt-1"
                  key={totalEquity}
                  initial={{ scale: 0.8 }}
                  animate={{ scale: 1 }}
                  transition={{ duration: 0.3 }}
                >
                  ${totalEquity.toFixed(2)}
                </motion.p>
              </motion.div>

              <motion.div
                className="p-3 rounded-lg bg-white/5 border border-white/10"
                whileHover={{ scale: 1.02 }}
              >
                <p className="text-xs font-medium text-slate-400 uppercase">
                  Available Cash
                </p>
                <p className="text-lg font-bold text-emerald-400 mt-1">
                  ${totalCash.toFixed(2)} ({cashPercentage.toFixed(1)}%)
                </p>
              </motion.div>

              <motion.div
                className="p-3 rounded-lg bg-white/5 border border-white/10"
                whileHover={{ scale: 1.02 }}
              >
                <p className="text-xs font-medium text-slate-400 uppercase">
                  Allocated
                </p>
                <p className="text-lg font-bold text-blue-400 mt-1">
                  ${totalAllocated.toFixed(2)} ({allocatedPercentage.toFixed(1)}
                  %)
                </p>
              </motion.div>
            </div>
          </div>
        </div>
      </GlassCard>

      {/* P&L Summary */}
      <GlassCard>
        <div className="space-y-4">
          <h3 className="text-lg font-semibold text-white">P&L Summary</h3>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <motion.div
              className="p-4 rounded-lg bg-gradient-to-br from-emerald-500/10 to-emerald-600/10 border border-emerald-500/30"
              whileHover={{ scale: 1.05 }}
            >
              <div className="flex items-center gap-2 mb-2">
                <TrendingUp className="w-4 h-4 text-emerald-400" />
                <p className="text-xs font-medium text-slate-400 uppercase">
                  Realized P&L
                </p>
              </div>
              <motion.p
                className="text-2xl font-bold text-emerald-400"
                key={realizedPnl}
                initial={{ scale: 0.8 }}
                animate={{ scale: 1 }}
              >
                {realizedPnl > 0 ? "+" : ""}${realizedPnl.toFixed(2)}
              </motion.p>
            </motion.div>

            <motion.div
              className={`p-4 rounded-lg border ${
                unrealizedPnl > 0
                  ? "bg-gradient-to-br from-blue-500/10 to-blue-600/10 border-blue-500/30"
                  : "bg-gradient-to-br from-red-500/10 to-red-600/10 border-red-500/30"
              }`}
              whileHover={{ scale: 1.05 }}
            >
              <div className="flex items-center gap-2 mb-2">
                <Activity
                  className="w-4 h-4"
                  style={{ color: unrealizedPnl > 0 ? "#06b6d4" : "#ef4444" }}
                />
                <p className="text-xs font-medium text-slate-400 uppercase">
                  Unrealized P&L
                </p>
              </div>
              <motion.p
                className={`text-2xl font-bold ${unrealizedPnl > 0 ? "text-cyan-400" : "text-red-400"}`}
                key={unrealizedPnl}
                initial={{ scale: 0.8 }}
                animate={{ scale: 1 }}
              >
                {unrealizedPnl > 0 ? "+" : ""}${unrealizedPnl.toFixed(2)}
              </motion.p>
            </motion.div>

            <motion.div
              className={`p-4 rounded-lg border ${
                unrealizedPnl + realizedPnl > 0
                  ? "bg-gradient-to-br from-emerald-500/10 to-emerald-600/10 border-emerald-500/30"
                  : "bg-gradient-to-br from-red-500/10 to-red-600/10 border-red-500/30"
              }`}
              whileHover={{ scale: 1.05 }}
            >
              <div className="flex items-center gap-2 mb-2">
                <TrendingUp
                  className="w-4 h-4"
                  style={{
                    color:
                      unrealizedPnl + realizedPnl > 0 ? "#10b981" : "#ef4444",
                  }}
                />
                <p className="text-xs font-medium text-slate-400 uppercase">
                  Total P&L
                </p>
              </div>
              <motion.p
                className={`text-2xl font-bold ${
                  unrealizedPnl + realizedPnl > 0
                    ? "text-emerald-400"
                    : "text-red-400"
                }`}
                key={unrealizedPnl + realizedPnl}
                initial={{ scale: 0.8 }}
                animate={{ scale: 1 }}
              >
                {unrealizedPnl + realizedPnl > 0 ? "+" : ""}$
                {(unrealizedPnl + realizedPnl).toFixed(2)}
              </motion.p>
            </motion.div>
          </div>
        </div>
      </GlassCard>

      {/* Open Positions */}
      {positions.length > 0 && (
        <GlassCard>
          <div className="space-y-4">
            <h3 className="text-lg font-semibold text-white">Open Positions</h3>

            <div className="space-y-2">
              {positions.map((position, index) => (
                <motion.div
                  key={position.symbol}
                  className="flex items-center justify-between p-3 rounded-lg bg-white/5 border border-white/10 hover:bg-white/10 transition-colors"
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: index * 0.05 }}
                  whileHover={{ scale: 1.02 }}
                >
                  <div className="flex-1">
                    <p className="font-medium text-white">{position.symbol}</p>
                    <p className="text-xs text-slate-400">
                      {position.quantity} @ ${position.entryPrice.toFixed(2)}
                    </p>
                  </div>

                  <div className="text-right">
                    <motion.p
                      className="font-semibold text-white"
                      key={position.value}
                      initial={{ scale: 0.8 }}
                      animate={{ scale: 1 }}
                    >
                      ${position.value.toFixed(2)}
                    </motion.p>
                    <p
                      className={`text-xs font-medium flex items-center justify-end gap-1 ${
                        position.pnl > 0 ? "text-emerald-400" : "text-red-400"
                      }`}
                    >
                      {position.pnl > 0 ? (
                        <TrendingUp className="w-3 h-3" />
                      ) : (
                        <TrendingDown className="w-3 h-3" />
                      )}
                      {position.pnl > 0 ? "+" : ""}${position.pnl.toFixed(2)} (
                      {position.pnlPercent.toFixed(1)}
                      %)
                    </p>
                  </div>
                </motion.div>
              ))}
            </div>
          </div>
        </GlassCard>
      )}
    </div>
  );
}

import axios from "axios";
